using System;
using System.Data.SqlClient;
using System.Web.Security;

public bool ValidateUser(string username, string password)
{
    var connectionString = ConfigurationManager.ConnectionStrings["DatabaseConnection"].ConnectionString;
    using (var connection = new SqlConnection(connectionString))
    {
        connection.Open();
        using (var command = new SqlCommand("SELECT COUNT(*) FROM Users WHERE Username = @Username AND Password = HashBytes('SHA1', @Password)", connection))
        {
            command.Parameters.AddWithValue("@Username", username);
            command.Parameters.AddWithValue("@Password", FormsAuthentication.HashPasswordForStoringInConfigFile(password, "SHA1"));
            var count = Convert.ToInt32(command.ExecuteScalar());
            return count > 0;
        }
    }
